{"command": "cd $WORKSPACE_DIR && python3 -c "
import docx
d = docx.Document('output/h1b-issue-memo.docx')
text = '\n'.join(p.text for p in d.paragraphs)
for t in d.tables:
    for row in t.rows:
        text += '\n' + ' | '.join(c.text for c in row.cells)
open('/tmp/deliverable_text.txt','w').write(text)
print('Total chars:', len(text))
""}

